class Solution:
    def solve(self):
        # Solution
        pipeline = [
            {'$map': {'input': '$author', 'as': 'author', 'in': {'$mergeObjects': {'name': '$$author.name', '_id': None}}}},
            {'$map': {'input': '$book', 'as': 'book', 'in': {'$mergeObjects': {'title': '$$book.title', 'price': '$$book.price', '_id': None}}}},
            {'$addFields': {'name': {'$ifNull': ['$author.name', None]}, 'title': {'$ifNull': ['$book.title', None]}, 'price': {'$ifNull': ['$book.price', None]}}}
        ]
        return pipeline;
